import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LyricLine {
  id: string;
  timestamp: number; // Time in seconds
  formattedTime: string; // [mm:ss.xx]
  text: string;
}

export interface AudioFile {
  file: File;
  previewUrl: string;
  base64: string;
}

export enum AppState {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  READY_TO_GENERATE = 'READY_TO_GENERATE',
  GENERATING = 'GENERATING',
  PLAYING = 'PLAYING',
  ERROR = 'ERROR'
}

import { LyricLine } from '../types';

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:audio/mp3;base64,")
      const base64String = result.split(',')[1];
      resolve(base64String);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const parseLrc = (lrcContent: string): LyricLine[] => {
  const lines = lrcContent.split('\n');
  const regex = /^\[(\d{2}):(\d{2})\.(\d{2,3})\](.*)$/;
  const parsedLines: LyricLine[] = [];

  lines.forEach((line, index) => {
    const match = line.trim().match(regex);
    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3].padEnd(3, '0'), 10); // Ensure ms is calculated correctly
      const text = match[4].trim();

      const totalSeconds = minutes * 60 + seconds + milliseconds / 1000;

      if (text) {
        parsedLines.push({
          id: `line-${index}`,
          timestamp: totalSeconds,
          formattedTime: `[${match[1]}:${match[2]}.${match[3]}]`,
          text: text
        });
      }
    }
  });

  return parsedLines;
};

export const formatTime = (seconds: number): string => {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

import { GoogleGenAI } from "@google/genai";

export const generateLyricsFromAudio = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Using gemini-3-pro-preview for better reasoning capabilities with audio/timestamps
    // as suggested by prompt guidance for complex tasks.
    const model = 'gemini-3-pro-preview'; 

    const prompt = `
      Listen to the following audio file carefully. 
      I need you to generate synchronized lyrics in LRC format.

      Rules:
      1. Listen to the vocals and transcribe the lyrics.
      2. Provide precise timestamps for each line in the format [mm:ss.xx].
      3. The output must be strictly the LRC content. Do not wrap it in markdown code blocks (like \`\`\`). 
      4. Do not add any introductory or concluding text. Just the lyrics.
      5. If there is a long instrumental section, mark it as [mm:ss.xx] (Instrumental).

      Example output format:
      [00:12.50] This is the first line of the song
      [00:15.20] And this is the second line
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Audio
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        // Thinking budget helps with the precision of timing
        thinkingConfig: { thinkingBudget: 2048 },
        maxOutputTokens: 8192, 
      }
    });

    if (!response.text) {
      throw new Error("No text generated from Gemini.");
    }

    // Clean up potential markdown formatting just in case
    let cleanText = response.text.trim();
    if (cleanText.startsWith('```lrc')) {
      cleanText = cleanText.replace('```lrc', '').replace('```', '');
    } else if (cleanText.startsWith('```')) {
      cleanText = cleanText.replace('```', '').replace('```', '');
    }

    return cleanText;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useCallback } from 'react';
import { Upload, Music } from 'lucide-react';

interface FileUploaderProps {
  onFileSelect: (file: File) => void;
}

const FileUploader: React.FC<FileUploaderProps> = ({ onFileSelect }) => {
  const handleDrop = useCallback((e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const file = e.dataTransfer.files[0];
      if (file.type.startsWith('audio/')) {
        onFileSelect(file);
      } else {
        alert("Por favor, suba apenas arquivos de áudio.");
      }
    }
  }, [onFileSelect]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelect(e.target.files[0]);
    }
  };

  return (
    <div 
      className="w-full max-w-xl mx-auto border-2 border-dashed border-zinc-700 rounded-2xl bg-zinc-900/50 hover:bg-zinc-900 transition-colors cursor-pointer group"
      onDragOver={(e) => e.preventDefault()}
      onDrop={handleDrop}
      onClick={() => document.getElementById('audio-input')?.click()}
    >
      <div className="flex flex-col items-center justify-center py-16 px-4">
        <div className="bg-zinc-800 p-4 rounded-full mb-4 group-hover:bg-indigo-600 transition-colors duration-300">
          <Upload className="w-8 h-8 text-white" />
        </div>
        <h3 className="text-xl font-semibold text-white mb-2">Subir Música</h3>
        <p className="text-zinc-400 text-center text-sm mb-4">
          Arraste e solte seu arquivo de áudio (MP3, WAV) aqui ou clique para selecionar.
        </p>
        <div className="flex items-center space-x-2 text-xs text-zinc-500 bg-zinc-800/50 px-3 py-1 rounded-full">
          <Music size={12} />
          <span>Suporta arquivos de até 20MB</span>
        </div>
        <input 
          type="file" 
          id="audio-input" 
          className="hidden" 
          accept="audio/*"
          onChange={handleChange}
        />
      </div>
    </div>
  );
};

export default FileUploader;

import React, { useEffect, useRef, useState } from 'react';
import { LyricLine } from '../types';
import { Play, Pause, RotateCcw, Download } from 'lucide-react';
import { formatTime } from '../utils/helpers';

interface LyricsViewProps {
  lyrics: LyricLine[];
  audioUrl: string;
  onReset: () => void;
  title?: string;
}

const LyricsView: React.FC<LyricsViewProps> = ({ lyrics, audioUrl, onReset, title = "Música Desconhecida" }) => {
  const audioRef = useRef<HTMLAudioElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [activeLineIndex, setActiveLineIndex] = useState<number>(-1);

  // Auto-scroll to active line
  useEffect(() => {
    if (activeLineIndex !== -1 && containerRef.current) {
      const activeElement = document.getElementById(`lyric-${activeLineIndex}`);
      if (activeElement) {
        activeElement.scrollIntoView({
          behavior: 'smooth',
          block: 'center',
        });
      }
    }
  }, [activeLineIndex]);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      const time = audioRef.current.currentTime;
      setCurrentTime(time);

      // Find active line
      const index = lyrics.findIndex((line, i) => {
        const nextLine = lyrics[i + 1];
        return time >= line.timestamp && (!nextLine || time < nextLine.timestamp);
      });

      if (index !== -1) {
        setActiveLineIndex(index);
      }
    }
  };

  const handleLoadedMetadata = () => {
    if (audioRef.current) {
      setDuration(audioRef.current.duration);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  const downloadLrc = () => {
    const content = lyrics.map(l => `${l.formattedTime} ${l.text}`).join('\n');
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'lyrics.lrc';
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="flex flex-col h-[600px] w-full max-w-4xl mx-auto bg-zinc-900 rounded-3xl overflow-hidden shadow-2xl border border-zinc-800">
      {/* Header / Player Controls */}
      <div className="bg-zinc-900 p-6 border-b border-zinc-800 z-10 relative">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h2 className="text-xl font-bold text-white truncate max-w-xs md:max-w-md">{title}</h2>
            <p className="text-zinc-400 text-sm">Letra Sincronizada com IA</p>
          </div>
          <div className="flex space-x-2">
            <button 
              onClick={downloadLrc}
              className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-800 rounded-full transition"
              title="Baixar .LRC"
            >
              <Download size={20} />
            </button>
            <button 
              onClick={onReset}
              className="p-2 text-zinc-400 hover:text-red-400 hover:bg-red-400/10 rounded-full transition"
              title="Nova Música"
            >
              <RotateCcw size={20} />
            </button>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={togglePlay}
            className="w-12 h-12 flex items-center justify-center rounded-full bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-500/30 transition-all transform hover:scale-105"
          >
            {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" className="ml-1" />}
          </button>

          <div className="flex-1">
            <input 
              type="range" 
              min="0" 
              max={duration || 100} 
              value={currentTime} 
              onChange={handleSeek}
              className="w-full h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:rounded-full hover:[&::-webkit-slider-thumb]:scale-125 transition-all"
            />
            <div className="flex justify-between text-xs text-zinc-500 mt-1">
              <span>{formatTime(currentTime)}</span>
              <span>{formatTime(duration)}</span>
            </div>
          </div>
        </div>

        <audio 
          ref={audioRef} 
          src={audioUrl} 
          onTimeUpdate={handleTimeUpdate}
          onLoadedMetadata={handleLoadedMetadata}
          onEnded={() => setIsPlaying(false)}
        />
      </div>

      {/* Lyrics Display */}
      <div 
        ref={containerRef}
        className="flex-1 overflow-y-auto p-8 relative bg-black/40 backdrop-blur-sm"
      >
        <div className="space-y-6 flex flex-col items-center text-center">
          {lyrics.length === 0 ? (
            <div className="text-zinc-500 mt-10">Nenhuma letra detectada.</div>
          ) : (
            lyrics.map((line, idx) => (
              <div
                key={line.id}
                id={`lyric-${idx}`}
                onClick={() => {
                  if (audioRef.current) {
                    audioRef.current.currentTime = line.timestamp;
                    audioRef.current.play();
                    setIsPlaying(true);
                  }
                }}
                className={`
                  transition-all duration-500 ease-in-out cursor-pointer max-w-2xl px-4 py-2 rounded-xl
                  ${idx === activeLineIndex 
                    ? 'text-white text-2xl md:text-3xl font-bold scale-105 bg-indigo-500/10 shadow-lg shadow-indigo-500/5 blur-0 opacity-100' 
                    : 'text-zinc-500 text-lg md:text-xl font-medium hover:text-zinc-300 opacity-60 blur-[0.5px]'}
                `}
              >
                {line.text}
              </div>
            ))
          )}
          {/* Spacer for bottom scrolling */}
          <div className="h-32"></div> 
        </div>
      </div>
    </div>
  );
};

export default LyricsView;

import React, { useState } from 'react';
import { AudioFile, LyricLine, AppState } from './types';
import FileUploader from './components/FileUploader';
import LyricsView from './components/LyricsView';
import { fileToBase64, parseLrc } from './utils/helpers';
import { generateLyricsFromAudio } from './services/geminiService';
import { Sparkles, Music2, Loader2, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [audioFile, setAudioFile] = useState<AudioFile | null>(null);
  const [lyrics, setLyrics] = useState<LyricLine[]>([]);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = async (file: File) => {
    try {
      setAppState(AppState.UPLOADING);
      setError(null);

      // Basic validation
      if (file.size > 25 * 1024 * 1024) { // 25MB limit
        throw new Error("Arquivo muito grande. Por favor envie arquivos menores que 25MB.");
      }

      const base64 = await fileToBase64(file);
      const previewUrl = URL.createObjectURL(file);

      setAudioFile({
        file,
        base64,
        previewUrl
      });

      setAppState(AppState.READY_TO_GENERATE);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Erro ao carregar arquivo.");
      setAppState(AppState.IDLE);
    }
  };

  const handleGenerate = async () => {
    if (!audioFile) return;

    try {
      setAppState(AppState.GENERATING);
      setError(null);

      const lrcText = await generateLyricsFromAudio(audioFile.base64, audioFile.file.type);
      const parsedLyrics = parseLrc(lrcText);

      if (parsedLyrics.length === 0) {
        // Fallback if parsing fails but text exists
        parsedLyrics.push({
          id: 'error',
          timestamp: 0,
          formattedTime: '[00:00.00]',
          text: lrcText.length > 500 ? lrcText.substring(0, 500) + '...' : lrcText
        });
        console.warn("LRC Parsing returned empty, showing raw text.");
      }

      setLyrics(parsedLyrics);
      setAppState(AppState.PLAYING);
    } catch (err) {
      console.error(err);
      setError("Falha ao gerar a letra com IA. Verifique sua chave API ou tente novamente.");
      setAppState(AppState.READY_TO_GENERATE);
    }
  };

  const handleReset = () => {
    if (audioFile) {
      URL.revokeObjectURL(audioFile.previewUrl);
    }
    setAudioFile(null);
    setLyrics([]);
    setError(null);
    setAppState(AppState.IDLE);
  };

  return (
    <div className="min-h-screen bg-black text-white selection:bg-indigo-500 selection:text-white">
      {/* Background Gradient */}
      <div className="fixed inset-0 z-0">
         <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-800/20 rounded-full blur-[120px]"></div>
         <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-800/20 rounded-full blur-[120px]"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8 md:py-16 flex flex-col items-center">

        {/* Header */}
        <div className="text-center mb-12">
          <div className="inline-flex items-center justify-center p-3 mb-4 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-xl">
            <Music2 className="w-8 h-8 text-indigo-500 mr-2" />
            <h1 className="text-3xl md:text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-zinc-400">
              SyncLyric AI
            </h1>
          </div>
          <p className="text-zinc-400 max-w-md mx-auto">
            Transforme qualquer arquivo de áudio em uma experiência de karaokê instantânea usando inteligência artificial.
          </p>
        </div>

        {/* Main Content Area */}
        <div className="w-full flex flex-col items-center">

          {error && (
            <div className="flex items-center space-x-2 bg-red-500/10 border border-red-500/20 text-red-400 px-4 py-3 rounded-xl mb-6 max-w-md w-full animate-in fade-in slide-in-from-top-4">
              <AlertCircle size={20} />
              <span className="text-sm">{error}</span>
            </div>
          )}

          {appState === AppState.IDLE && (
            <div className="animate-in fade-in zoom-in-95 duration-500 w-full flex justify-center">
              <FileUploader onFileSelect={handleFileSelect} />
            </div>
          )}

          {appState === AppState.UPLOADING && (
            <div className="flex flex-col items-center justify-center space-y-4 py-12 animate-in fade-in">
              <Loader2 className="w-10 h-10 text-indigo-500 animate-spin" />
              <p className="text-zinc-400">Processando arquivo...</p>
            </div>
          )}

          {appState === AppState.READY_TO_GENERATE && audioFile && (
             <div className="w-full max-w-md bg-zinc-900/80 backdrop-blur-md border border-zinc-800 rounded-3xl p-8 text-center animate-in fade-in slide-in-from-bottom-8">
                <div className="w-16 h-16 bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-6">
                  <Music2 className="w-8 h-8 text-indigo-400" />
                </div>
                <h3 className="text-xl font-semibold text-white mb-2 truncate">
                  {audioFile.file.name}
                </h3>
                <p className="text-zinc-500 text-sm mb-8">
                  {(audioFile.file.size / (1024 * 1024)).toFixed(2)} MB • {audioFile.file.type}
                </p>

                <div className="flex gap-3">
                  <button 
                    onClick={handleReset}
                    className="flex-1 px-4 py-3 bg-zinc-800 hover:bg-zinc-700 text-white rounded-xl transition-colors font-medium"
                  >
                    Trocar
                  </button>
                  <button 
                    onClick={handleGenerate}
                    className="flex-1 px-4 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl transition-all font-medium flex items-center justify-center shadow-lg shadow-indigo-600/20 hover:shadow-indigo-600/40"
                  >
                    <Sparkles size={18} className="mr-2" />
                    Gerar Letra
                  </button>
                </div>
             </div>
          )}

          {appState === AppState.GENERATING && (
            <div className="flex flex-col items-center justify-center space-y-6 py-12 animate-in fade-in max-w-md text-center">
              <div className="relative">
                <div className="absolute inset-0 bg-indigo-500 blur-xl opacity-20 rounded-full"></div>
                <Loader2 className="w-12 h-12 text-indigo-500 animate-spin relative z-10" />
              </div>
              <div>
                <h3 className="text-lg font-medium text-white mb-2">A IA está ouvindo...</h3>
                <p className="text-zinc-500 text-sm">
                  Isso pode levar até um minuto dependendo do tamanho da música.
                  Estamos transcrevendo e sincronizando os tempos.
                </p>
              </div>
            </div>
          )}

          {appState === AppState.PLAYING && audioFile && (
            <div className="w-full animate-in fade-in zoom-in-95 duration-500">
              <LyricsView 
                lyrics={lyrics} 
                audioUrl={audioFile.previewUrl} 
                onReset={handleReset}
                title={audioFile.file.name}
              />
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="mt-16 text-zinc-600 text-xs">
          Powered by Gemini 2.0 Flash/Pro
        </div>
      </div>
    </div>
  );
};

export default App;

export interface LyricLine {
  id: string;
  timestamp: number | null; // Time in seconds (null if not yet synced)
  formattedTime: string; // [mm:ss.xx]
  text: string;
}

export interface AudioFile {
  file: File;
  previewUrl: string;
  base64: string;
}

export enum AppState {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  READY_TO_GENERATE = 'READY_TO_GENERATE',
  GENERATING = 'GENERATING',
  PLAYING = 'PLAYING',
  ERROR = 'ERROR'
}

import { LyricLine } from '../types';

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64String = result.split(',')[1];
      resolve(base64String);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const parseLyrics = (content: string): LyricLine[] => {
  const lines = content.split('\n').filter(line => line.trim() !== '');

  return lines.map((line, index) => {
    const cleanLine = line.trim();
    // Check if it already has timestamp (in case of re-import or hybrid)
    const match = cleanLine.match(/^\[(\d{2}):(\d{2})\.(\d{2,3})\](.*)$/);

    if (match) {
      const minutes = parseInt(match[1], 10);
      const seconds = parseInt(match[2], 10);
      const milliseconds = parseInt(match[3].padEnd(3, '0'), 10);
      const text = match[4].trim();
      const totalSeconds = minutes * 60 + seconds + milliseconds / 1000;

      return {
        id: `line-${index}`,
        timestamp: totalSeconds,
        formattedTime: `[${match[1]}:${match[2]}.${match[3]}]`,
        text: text
      };
    } else {
      // Plain text, unsynced
      return {
        id: `line-${index}`,
        timestamp: null,
        formattedTime: '[--:--.--]',
        text: cleanLine
      };
    }
  });
};

export const formatTime = (seconds: number): string => {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  const ms = Math.floor((seconds % 1) * 100);
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}`;
};

import { GoogleGenAI } from "@google/genai";

export const generateLyricsFromAudio = async (base64Audio: string, mimeType: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // gemini-3-flash-preview is sufficient and faster for pure transcription
    const model = 'gemini-3-flash-preview'; 

    const prompt = `
      Listen to the following audio file.
      Transcribe the lyrics exactly as they are sung.

      Rules:
      1. Return ONLY the plain text lyrics.
      2. Put each line of the song on a new line.
      3. Do NOT include timestamps.
      4. Do NOT include header lines like "Verse 1" or "Chorus".
      5. Do NOT include markdown blocks.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Audio
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        // Lower thinking budget as this is a simpler transcription task
        thinkingConfig: { thinkingBudget: 0 },
      }
    });

    if (!response.text) {
      throw new Error("No text generated from Gemini.");
    }

    let cleanText = response.text.trim();
    if (cleanText.startsWith('```')) {
      cleanText = cleanText.replace(/^```[a-z]*\n/, '').replace(/\n```$/, '');
    }

    return cleanText;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
