import React, { useEffect, useRef, useState, useCallback } from 'react';
import { LyricLine } from '../types';
import { Play, Pause, RotateCcw, Download, Check } from 'lucide-react';
import { formatTime } from '../utils/helpers';

interface LyricsViewProps {
  lyrics: LyricLine[];
  setLyrics: (lyrics: LyricLine[]) => void;
  audioUrl: string;
  onReset: () => void;
  title?: string;
}

const LyricsView: React.FC<LyricsViewProps> = ({ lyrics, setLyrics, audioUrl, onReset, title = "Música Desconhecida" }) => {
  const audioRef = useRef<HTMLAudioElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  // Find the index of the first line that doesn't have a timestamp yet
  const nextUnsyncedIndex = lyrics.findIndex(l => l.timestamp === null);

  // For playback highlighting (auto-scroll)
  const activePlayIndex = lyrics.findIndex((line, i) => {
    if (line.timestamp === null) return false;
    const nextLine = lyrics.slice(i + 1).find(l => l.timestamp !== null);
    return currentTime >= line.timestamp && (!nextLine || currentTime < nextLine.timestamp);
  });

  // Scroll logic
  useEffect(() => {
    // If we are playing and all synced, follow playback. 
    // If we are syncing, follow the cursor (nextUnsyncedIndex).
    const targetIndex = nextUnsyncedIndex !== -1 ? nextUnsyncedIndex : activePlayIndex;

    if (targetIndex !== -1 && containerRef.current) {
      const activeElement = document.getElementById(`lyric-${targetIndex}`);
      if (activeElement) {
        activeElement.scrollIntoView({
          behavior: 'smooth',
          block: 'center',
        });
      }
    }
  }, [activePlayIndex, nextUnsyncedIndex]);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
    }
  };

  const handleLoadedMetadata = () => {
    if (audioRef.current) {
      setDuration(audioRef.current.duration);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  // The Manual Sync Action
  const syncCurrentLine = useCallback(() => {
    if (nextUnsyncedIndex === -1 || !audioRef.current) return;

    const currentTimestamp = audioRef.current.currentTime;

    // Create new array with updated timestamp
    const newLyrics = [...lyrics];
    newLyrics[nextUnsyncedIndex] = {
      ...newLyrics[nextUnsyncedIndex],
      timestamp: currentTimestamp,
      formattedTime: `[${formatTime(currentTimestamp)}]`
    };

    setLyrics(newLyrics);
  }, [lyrics, nextUnsyncedIndex, setLyrics]);

  // Keyboard shortcut 'v' or Space (if focused)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key.toLowerCase() === 'v') {
        e.preventDefault(); // Prevent default if any
        syncCurrentLine();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [syncCurrentLine]);

  const downloadLrc = () => {
    const content = lyrics
      .filter(l => l.timestamp !== null)
      .map(l => `${l.formattedTime} ${l.text}`)
      .join('\n');

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'lyrics.lrc';
    a.click();
    URL.revokeObjectURL(url);
  };

  // Calculate progress of syncing
  const syncedCount = lyrics.filter(l => l.timestamp !== null).length;
  const progressPercent = (syncedCount / lyrics.length) * 100;

  return (
    <div className="flex flex-col h-[700px] w-full max-w-5xl mx-auto bg-zinc-900 rounded-3xl overflow-hidden shadow-2xl border border-zinc-800">

      {/* Header & Controls */}
      <div className="bg-zinc-900 p-6 border-b border-zinc-800 z-10 relative">
        <div className="flex items-center justify-between mb-4">
          <div className="flex-1 min-w-0 mr-4">
            <h2 className="text-xl font-bold text-white truncate">{title}</h2>
            <p className="text-zinc-400 text-sm flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${nextUnsyncedIndex === -1 ? 'bg-green-500' : 'bg-amber-500'}`}></span>
              {nextUnsyncedIndex === -1 ? "Sincronização Completa!" : "Modo de Sincronização Manual"}
            </p>
          </div>
          <div className="flex space-x-2">
            <button 
              onClick={downloadLrc}
              className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-800 rounded-full transition"
              title="Baixar .LRC"
            >
              <Download size={20} />
            </button>
            <button 
              onClick={onReset}
              className="p-2 text-zinc-400 hover:text-red-400 hover:bg-red-400/10 rounded-full transition"
              title="Nova Música"
            >
              <RotateCcw size={20} />
            </button>
          </div>
        </div>

        {/* Sync Progress Bar */}
        <div className="w-full bg-zinc-800 h-1.5 rounded-full mb-6 overflow-hidden">
          <div 
            className="h-full bg-indigo-500 transition-all duration-300" 
            style={{ width: `${progressPercent}%` }}
          ></div>
        </div>

        <div className="flex items-center gap-6">
          <button 
            onClick={togglePlay}
            className="w-14 h-14 flex-shrink-0 flex items-center justify-center rounded-full bg-white text-black hover:bg-zinc-200 transition-all transform hover:scale-105 shadow-lg"
          >
            {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" className="ml-1" />}
          </button>

          <div className="flex-1 flex flex-col justify-center">
            <input 
              type="range" 
              min="0" 
              max={duration || 100} 
              value={currentTime} 
              onChange={handleSeek}
              className="w-full h-2 bg-zinc-700 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:bg-indigo-500 [&::-webkit-slider-thumb]:rounded-full hover:[&::-webkit-slider-thumb]:scale-110 transition-all"
            />
            <div className="flex justify-between text-xs text-zinc-500 mt-2 font-mono">
              <span>{formatTime(currentTime)}</span>
              <span>{formatTime(duration)}</span>
            </div>
          </div>

          {/* THE BIG SYNC BUTTON */}
          <button
            onClick={syncCurrentLine}
            disabled={nextUnsyncedIndex === -1}
            className={`
              hidden md:flex flex-col items-center justify-center w-24 h-20 rounded-xl border-b-4 active:border-b-0 active:translate-y-1 transition-all
              ${nextUnsyncedIndex === -1 
                ? 'bg-zinc-800 border-zinc-700 text-zinc-500 cursor-not-allowed' 
                : 'bg-indigo-600 border-indigo-800 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-500/20'}
            `}
          >
            <span className="text-2xl font-black">V</span>
            <span className="text-[10px] uppercase font-bold tracking-wider">Sync</span>
          </button>
        </div>
      </div>

      {/* Lyrics Display */}
      <div 
        ref={containerRef}
        className="flex-1 overflow-y-auto p-6 relative bg-black/40 backdrop-blur-sm scroll-smooth"
      >
        <div className="space-y-4 flex flex-col items-center text-center">
          {lyrics.length === 0 ? (
            <div className="text-zinc-500 mt-10">Nenhuma letra detectada.</div>
          ) : (
            lyrics.map((line, idx) => {
              const isSynced = line.timestamp !== null;
              const isNext = idx === nextUnsyncedIndex;
              const isPast = isSynced && currentTime > (line.timestamp || 0);
              const isActive = isSynced && idx === activePlayIndex;

              return (
                <div
                  key={line.id}
                  id={`lyric-${idx}`}
                  className={`
                    relative transition-all duration-300 ease-in-out px-6 py-3 rounded-2xl max-w-3xl w-full
                    border border-transparent
                    ${isActive 
                      ? 'bg-indigo-500/20 text-white scale-105 border-indigo-500/30' 
                      : ''}
                    ${isNext 
                      ? 'bg-zinc-800/80 text-white border-zinc-700 ring-2 ring-indigo-500 ring-offset-2 ring-offset-zinc-900 scale-100 opacity-100 z-10 shadow-xl' 
                      : ''}
                    ${!isSynced && !isNext 
                      ? 'text-zinc-600 opacity-50 scale-95' 
                      : ''}
                    ${isSynced && !isActive 
                      ? 'text-zinc-400 hover:text-zinc-200 cursor-pointer' 
                      : ''}
                  `}
                  onClick={() => {
                    // Clicking a synced line seeks to it
                    if (isSynced && audioRef.current && line.timestamp !== null) {
                      audioRef.current.currentTime = line.timestamp;
                      audioRef.current.play();
                      setIsPlaying(true);
                    }
                  }}
                >
                  <div className="flex items-center justify-between gap-4">
                    {/* Time or Status */}
                    <div className="w-20 text-xs font-mono text-zinc-500 text-right flex-shrink-0">
                      {isSynced ? (
                        formatTime(line.timestamp!)
                      ) : (
                        isNext ? <span className="text-indigo-400 font-bold animate-pulse">AGORA</span> : "--:--"
                      )}
                    </div>

                    {/* Text */}
                    <div className={`flex-1 text-lg md:text-xl font-medium ${isNext ? 'font-bold' : ''}`}>
                      {line.text}
                    </div>

                    {/* Indicator */}
                    <div className="w-6 flex-shrink-0">
                      {isSynced && <Check size={16} className="text-green-500/50" />}
                      {isNext && (
                         <button 
                           onClick={(e) => { e.stopPropagation(); syncCurrentLine(); }}
                           className="md:hidden w-8 h-8 flex items-center justify-center bg-indigo-600 rounded-full text-white shadow-lg active:scale-90"
                         >
                           V
                         </button>
                      )}
                    </div>
                  </div>
                </div>
              );
            })
          )}
          <div className="h-[40vh]"></div> 
        </div>
      </div>

      {/* Mobile Sticky Button */}
      {nextUnsyncedIndex !== -1 && (
        <div className="md:hidden absolute bottom-6 right-6 z-50">
           <button 
             onClick={syncCurrentLine}
             className="w-16 h-16 bg-indigo-600 rounded-full text-white shadow-xl shadow-indigo-600/30 flex items-center justify-center font-bold text-2xl active:scale-95 transition-transform border-4 border-zinc-900"
           >
             V
           </button>
        </div>
      )}
    </div>
  );
};

export default LyricsView;

import React, { useState } from 'react';
import { AudioFile, LyricLine, AppState } from './types';
import FileUploader from './components/FileUploader';
import LyricsView from './components/LyricsView';
import { fileToBase64, parseLyrics } from './utils/helpers';
import { generateLyricsFromAudio } from './services/geminiService';
import { Sparkles, Music2, Loader2, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [audioFile, setAudioFile] = useState<AudioFile | null>(null);
  const [lyrics, setLyrics] = useState<LyricLine[]>([]);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = async (file: File) => {
    try {
      setAppState(AppState.UPLOADING);
      setError(null);

      if (file.size > 25 * 1024 * 1024) { 
        throw new Error("Arquivo muito grande. Por favor envie arquivos menores que 25MB.");
      }

      const base64 = await fileToBase64(file);
      const previewUrl = URL.createObjectURL(file);

      setAudioFile({
        file,
        base64,
        previewUrl
      });

      setAppState(AppState.READY_TO_GENERATE);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Erro ao carregar arquivo.");
      setAppState(AppState.IDLE);
    }
  };

  const handleGenerate = async () => {
    if (!audioFile) return;

    try {
      setAppState(AppState.GENERATING);
      setError(null);

      const rawText = await generateLyricsFromAudio(audioFile.base64, audioFile.file.type);
      const parsedLyrics = parseLyrics(rawText);

      if (parsedLyrics.length === 0) {
        parsedLyrics.push({
          id: 'error',
          timestamp: null,
          formattedTime: '[--:--]',
          text: rawText.length > 500 ? rawText.substring(0, 500) + '...' : rawText
        });
      }

      setLyrics(parsedLyrics);
      setAppState(AppState.PLAYING);
    } catch (err) {
      console.error(err);
      setError("Falha ao transcrever. Tente novamente.");
      setAppState(AppState.READY_TO_GENERATE);
    }
  };

  const handleReset = () => {
    if (audioFile) {
      URL.revokeObjectURL(audioFile.previewUrl);
    }
    setAudioFile(null);
    setLyrics([]);
    setError(null);
    setAppState(AppState.IDLE);
  };

  return (
    <div className="min-h-screen bg-black text-white selection:bg-indigo-500 selection:text-white">
      <div className="fixed inset-0 z-0">
         <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-800/20 rounded-full blur-[120px]"></div>
         <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-800/20 rounded-full blur-[120px]"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8 md:py-16 flex flex-col items-center">

        <div className="text-center mb-12">
          <div className="inline-flex items-center justify-center p-3 mb-4 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-xl">
            <Music2 className="w-8 h-8 text-indigo-500 mr-2" />
            <h1 className="text-3xl md:text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-zinc-400">
              SyncLyric AI
            </h1>
          </div>
          <p className="text-zinc-400 max-w-md mx-auto">
            1. Envie a música. 2. A IA transcreve. 3. Você aperta <strong>V</strong> para sincronizar.
          </p>
        </div>

        <div className="w-full flex flex-col items-center">

          {error && (
            <div className="flex items-center space-x-2 bg-red-500/10 border border-red-500/20 text-red-400 px-4 py-3 rounded-xl mb-6 max-w-md w-full animate-in fade-in slide-in-from-top-4">
              <AlertCircle size={20} />
              <span className="text-sm">{error}</span>
            </div>
          )}

          {appState === AppState.IDLE && (
            <div className="animate-in fade-in zoom-in-95 duration-500 w-full flex justify-center">
              <FileUploader onFileSelect={handleFileSelect} />
            </div>
          )}

          {appState === AppState.UPLOADING && (
            <div className="flex flex-col items-center justify-center space-y-4 py-12 animate-in fade-in">
              <Loader2 className="w-10 h-10 text-indigo-500 animate-spin" />
              <p className="text-zinc-400">Processando arquivo...</p>
            </div>
          )}

          {appState === AppState.READY_TO_GENERATE && audioFile && (
             <div className="w-full max-w-md bg-zinc-900/80 backdrop-blur-md border border-zinc-800 rounded-3xl p-8 text-center animate-in fade-in slide-in-from-bottom-8">
                <div className="w-16 h-16 bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-6">
                  <Music2 className="w-8 h-8 text-indigo-400" />
                </div>
                <h3 className="text-xl font-semibold text-white mb-2 truncate">
                  {audioFile.file.name}
                </h3>
                <p className="text-zinc-500 text-sm mb-8">
                  {(audioFile.file.size / (1024 * 1024)).toFixed(2)} MB • {audioFile.file.type}
                </p>

                <div className="flex gap-3">
                  <button 
                    onClick={handleReset}
                    className="flex-1 px-4 py-3 bg-zinc-800 hover:bg-zinc-700 text-white rounded-xl transition-colors font-medium"
                  >
                    Trocar
                  </button>
                  <button 
                    onClick={handleGenerate}
                    className="flex-1 px-4 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl transition-all font-medium flex items-center justify-center shadow-lg shadow-indigo-600/20 hover:shadow-indigo-600/40"
                  >
                    <Sparkles size={18} className="mr-2" />
                    Transcrever
                  </button>
                </div>
             </div>
          )}

          {appState === AppState.GENERATING && (
            <div className="flex flex-col items-center justify-center space-y-6 py-12 animate-in fade-in max-w-md text-center">
              <div className="relative">
                <div className="absolute inset-0 bg-indigo-500 blur-xl opacity-20 rounded-full"></div>
                <Loader2 className="w-12 h-12 text-indigo-500 animate-spin relative z-10" />
              </div>
              <div>
                <h3 className="text-lg font-medium text-white mb-2">Transcrevendo áudio...</h3>
                <p className="text-zinc-500 text-sm">
                  Estamos extraindo a letra. Em breve você poderá sincronizá-la manualmente.
                </p>
              </div>
            </div>
          )}

          {appState === AppState.PLAYING && audioFile && (
            <div className="w-full animate-in fade-in zoom-in-95 duration-500">
              <LyricsView 
                lyrics={lyrics}
                setLyrics={setLyrics}
                audioUrl={audioFile.previewUrl} 
                onReset={handleReset}
                title={audioFile.file.name}
              />
            </div>
          )}
        </div>

        <div className="mt-16 text-zinc-600 text-xs">
          Powered by Gemini 2.0 Flash/Pro
        </div>
      </div>
    </div>
  );
};

export default App;

