const LyricsView: React.FC<LyricsViewProps> = ({ lyrics, setLyrics, audioUrl, onReset, title = "Música Desconhecida" }) => {
  const audioRef = useRef<HTMLAudioElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
